  ('real-estate-moex-01004', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依我國民法之規定，當胎兒為繼承人時，他繼承人如未保留胎兒之應繼分而分割遺產者，其分割行為之 效力如何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01005', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙為夫妻育有二女丙與丁，甲為傳香火認識已婚之戊女，同居一年後生下己男，甲把己接回家中同住 將其養育成人，但丙與己相處極為不睦，丙亦曾對己口出穢言且被判刑確定，某日丙與己再起爭執，己 一時失手將丙刺成重傷，丁見狀，起身亦把己刺成重傷，丁與己嗣後雙雙被判重刑確定，乙為此人倫悲 劇在眾人前以不堪字眼侮辱甲，甲亦默默承受，但隔日即因傷心過度辭世。試問本案中，何人對甲無繼 承權？', '["乙", "丙", "丁", "己"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01006', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關拋棄繼承之敘述，下列何者正確？', '["向戶政機關為之", "得以言詞或書面為之", "於被繼承人死亡之時起3個月內為之", "繼承之拋棄，溯及於繼承開始時發生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01007', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列那種情形，甲所立的遺囑為有效？', '["甲6歲，經由其父母之代理而立之遺囑", "甲15歲，預立遺囑後，得其父母之追認", "甲10歲，但已得其父母之同意而立之遺囑", "甲17歲，未得其父母之允許或承認而立之遺囑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01008', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'essay', 'A建地面積130坪，乙為A地所有權人，於民國（下同）101年7月26日委由甲不
動產經紀人代為尋找買主，甲乙簽訂專任委託銷售契約約定：「……二、委託底價：
每坪 20萬元（合計 2,600萬元）；三、服務費：超過每坪20萬元以上，均算為
『服務費』予甲；四、委託期限：自101年7月26日至101年10月25日止……」
甲於101年8月26日找到丙願意以每坪21萬元購買，乙丙雙方碰面後，乙表示要
先塗銷 A 地原有的抵押權登記，再與丙約期簽約。之後，一直到 101 年 10 月 25
日前止，乙均以抵押權登記尚未塗銷為理由，拒絕簽約。102 年 2 月 25 日後乙丙
雙方合意辦理A地所有權移轉登記完畢，而買賣價格即為每坪21萬元。甲發現後
即起訴，請求乙給付130萬元服務費，請問有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01009', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '乙企業向甲銀行申請企業貸款5,000萬元，乙提供其所有的A素地為擔保，設定抵
押權給甲，甲同意貸款，但要求乙同意將 A 素地同時設定地上權給甲，然而就設
定地上權的契約，並未約定權利金或地租的給付。請問雙方設定抵押權與地上權的效
力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01010', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙通謀虛偽意思表示，將甲所有之A地賣予乙並移轉登記為乙所有。嗣後乙擅自將A地出賣丙，並 完成移轉登記，惟丙不知甲、乙通謀虛偽意思表示之事。下列敘述，何者正確？', '["甲與乙間關於A地之買賣契約效力未定", "甲與乙間關於A地之買賣契約無效", "甲與乙間關於A地之買賣契約有效", "乙與丙間關於A地之買賣契約無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01011', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '承上題，嗣後丙將A地又賣給丁，並完成移轉登記。A地之所有權應屬何人？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01012', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲對乙表示，如不贈與家傳骨董，即告發其走私之事，乙被迫贈與之。該贈與契約之效力為：', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01013', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列契約，何者不得聲請法院撤銷？', '["因急迫輕率無經驗而訂立週年利率高達60%之高利貸契約", "乘他人急迫輕率無經驗而訂立之婚約", "債務人所訂立有害及債權之贈與契約", "因被詐欺或被脅迫而訂立之離婚協議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
